   101→    @GET
   102→    @Operation(summary = "List all active connectors")
   103→    public Response listConnectors(
   104→        final @Context UriInfo uriInfo,
   105→        final @Context HttpHeaders headers
   106→    ) {
   107→        if (uriInfo.getQueryParameters().containsKey("expand")) {
   108→            Map<String, Map<String, Object>> out = new HashMap<>();
   109→            for (String connector : herder.connectors()) {
   110→                try {
   111→                    Map<String, Object> connectorExpansions = new HashMap<>();
   112→                    for (String expansion : uriInfo.getQueryParameters().get("expand")) {
   113→                        switch (expansion) {
   114→                            case "status":
   115→                                connectorExpansions.put("status", herder.connectorStatus(connector));
   116→                                break;
   117→                            case "info":
   118→                                connectorExpansions.put("info", herder.connectorInfo(connector));
   119→                                break;
   120→                            default:
   121→                                log.info("Ignoring unknown expansion type {}", expansion);
   122→                        }
   123→                    }
   124→                    out.put(connector, connectorExpansions);
   125→                } catch (NotFoundException e) {
   126→                    // this likely means that a connector has been removed while we look its info up
   127→                    // we can just not include this connector in the return entity
   128→                    log.debug("Unable to get connector info for {} on this worker", connector);
   129→                }
   130→
   131→            }
   132→            return Response.ok(out).build();
   133→        } else {
   134→            return Response.ok(herder.connectors()).build();
   135→        }
   136→    }
