   227→    protected final void initializeResources() {
   228→        log.info("Initializing REST resources");
   229→
   230→        ResourceConfig resourceConfig = newResourceConfig();
   231→        Collection<Class<?>> regularResources = regularResources();
   232→        regularResources.forEach(resourceConfig::register);
   233→        configureRegularResources(resourceConfig);
   234→
   235→        List<String> adminListeners = config.adminListeners();
   236→        ResourceConfig adminResourceConfig;
   237→        if (adminListeners != null && adminListeners.isEmpty()) {
   238→            log.info("Skipping adding admin resources");
   239→            // set up adminResource but add no handlers to it
   240→            adminResourceConfig = resourceConfig;
   241→        } else {
   242→            if (adminListeners == null) {
   243→                log.info("Adding admin resources to main listener");
   244→                adminResourceConfig = resourceConfig;
   245→            } else {
   246→                // TODO: we need to check if these listeners are same as 'listeners'
   247→                // TODO: the following code assumes that they are different
   248→                log.info("Adding admin resources to admin listener");
   249→                adminResourceConfig = newResourceConfig();
   250→            }
   251→            Collection<Class<?>> adminResources = adminResources();
   252→            adminResources.forEach(adminResourceConfig::register);
   253→            configureAdminResources(adminResourceConfig);
   254→        }
   255→
   256→        ServletContainer servletContainer = new ServletContainer(resourceConfig);
   257→        ServletHolder servletHolder = new ServletHolder(servletContainer);
   258→        List<Handler> contextHandlers = new ArrayList<>();
   259→
   260→        ServletContextHandler context = new ServletContextHandler(ServletContextHandler.SESSIONS);
   261→        context.setContextPath("/");
   262→        context.addServlet(servletHolder, "/*");
   263→        contextHandlers.add(context);
   264→
   265→        ServletContextHandler adminContext = null;
   266→        if (adminResourceConfig != resourceConfig) {
   267→            adminContext = new ServletContextHandler(ServletContextHandler.SESSIONS);
   268→            ServletHolder adminServletHolder = new ServletHolder(new ServletContainer(adminResourceConfig));
   269→            adminContext.setContextPath("/");
   270→            adminContext.addServlet(adminServletHolder, "/*");
   271→            adminContext.setVirtualHosts(List.of("@" + ADMIN_SERVER_CONNECTOR_NAME));
   272→            contextHandlers.add(adminContext);
   273→        }
   274→
   275→        String allowedOrigins = config.allowedOrigins();
   276→        if (!Utils.isBlank(allowedOrigins)) {
   277→            CrossOriginHandler crossOriginHandler = new CrossOriginHandler();
   278→            crossOriginHandler.setAllowedOriginPatterns(Set.of(allowedOrigins.split(",")));
   279→            String allowedMethods = config.allowedMethods();
   280→            if (!Utils.isBlank(allowedMethods)) {
   281→                crossOriginHandler.setAllowedMethods(Set.of(allowedMethods.split(",")));
   282→            }
   283→            // Setting to true matches the previously used CrossOriginFilter
   284→            crossOriginHandler.setDeliverPreflightRequests(true);
   285→            context.insertHandler(crossOriginHandler);
   286→        }
   287→
   288→        String headerConfig = config.responseHeaders();
   289→        if (!Utils.isBlank(headerConfig)) {
   290→            configureHttpResponseHeaderFilter(context, headerConfig);
   291→        }
   292→
   293→        handlers.setHandlers(contextHandlers.toArray(new Handler[0]));
   294→        try {
   295→            context.start();
   296→        } catch (Exception e) {
   297→            throw new ConnectException("Unable to initialize REST resources", e);
   298→        }
   299→
   300→        if (adminResourceConfig != resourceConfig) {
   301→            try {
   302→                log.debug("Starting admin context");
   303→                adminContext.start();
   304→            } catch (Exception e) {
   305→                throw new ConnectException("Unable to initialize Admin REST resources", e);
   306→            }
   307→        }
   308→
   309→        log.info("REST resources initialized; server is started and ready to handle requests");
   310→    }
