   396→    /**
   397→     * Get the URL to advertise to other workers and clients. This uses the default connector from the embedded Jetty
   398→     * server, unless overrides for advertised hostname and/or port are provided via configs. {@link #initializeServer()}
   399→     * must be invoked successfully before calling this method.
   400→     */
   401→    public URI advertisedUrl() {
   402→        UriBuilder builder = UriBuilder.fromUri(jettyServer.getURI());
   403→
   404→        String advertisedSecurityProtocol = determineAdvertisedProtocol();
   405→        ServerConnector serverConnector = findConnector(advertisedSecurityProtocol);
   406→        builder.scheme(advertisedSecurityProtocol);
   407→
   408→        String advertisedHostname = config.advertisedHostName();
   409→        if (advertisedHostname != null && !advertisedHostname.isEmpty())
   410→            builder.host(advertisedHostname);
   411→        else if (serverConnector != null && serverConnector.getHost() != null && !serverConnector.getHost().isEmpty())
   412→            builder.host(serverConnector.getHost());
   413→
   414→        Integer advertisedPort = config.advertisedPort();
   415→        if (advertisedPort != null)
   416→            builder.port(advertisedPort);
   417→        else if (serverConnector != null && serverConnector.getPort() > 0)
   418→            builder.port(serverConnector.getPort());
   419→        else if (serverConnector != null && serverConnector.getLocalPort() > 0)
   420→            builder.port(serverConnector.getLocalPort());
   421→
   422→        log.info("Advertised URI: {}", builder.build());
   423→
   424→        return builder.build();
   425→    }
