   429→     */
   430→    public URI adminUrl() {
   431→        ServerConnector adminConnector = null;
   432→        for (Connector connector : jettyServer.getConnectors()) {
   433→            if (ADMIN_SERVER_CONNECTOR_NAME.equals(connector.getName()))
   434→                adminConnector = (ServerConnector) connector;
   435→        }
   436→
   437→        if (adminConnector == null) {
   438→            List<String> adminListeners = config.adminListeners();
   439→            if (adminListeners == null) {
   440→                return advertisedUrl();
   441→            } else if (adminListeners.isEmpty()) {
   442→                return null;
   443→            } else {
   444→                log.error("No admin connector found for listeners {}", adminListeners);
   445→                return null;
   446→            }
   447→        }
